query:
SELECT 
  SUM(CAST(committedAmount AS DECIMAL(15,2))) as total_committed,
  SUM(CASE WHEN committedAmount > 0 THEN 1 ELSE 0 END) as has_committed,
  SUM(CASE WHEN committedAmount = '0' OR committedAmount = '0.00' THEN 1 ELSE 0 END) as zero_committed
FROM budget_lines WHERE projectId = '712-driggs';

SELECT id, name, budgetAmount, committedAmount FROM budget_lines WHERE projectId = '712-driggs' AND CAST(committedAmount AS DECIMAL) > 0 LIMIT 20;

